script.text:
      &JavascriptReportInit;

function load$&defaultName;(g) {
  g._$c = g._getColumnOrder('ma_so');
  g._$f = g._getColumnOrder('chi_tieu');
  g._$gt = g._getColumnOrder('gt');
  g._$ts = g._getColumnOrder('ts');
  g._$danh_gia = g._getColumnOrder('danh_gia');
  g._$cotdg = (g._language == 'v' ? '1': '2');
  g._$cotgt = '3';
  g._$cotts = '5';

  g.add_itemValueChanged(onChange$&defaultName;);
  g.add_commandEvent(on$&defaultName;$ExecuteCommand);
  g.add_onResponseComplete(on$&defaultName;$ResponseComplete);
}

function dispose$&defaultName;(g) {
  g._arrValue = null;
  try { g.remove_commandEvent(on$&defaultName;$ExecuteCommand); } catch (ex) {}
  try { g.remove_onResponseComplete(on$&defaultName;$ResponseComplete); } catch (ex) {}
  try { g.remove_itemValueChanged(onChange$&defaultName;); } catch (ex) {}
}
function on$&defaultName;$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'Save':
      request$Posting(g, action);
      break;
    case 'Clear':
      if (g._rowCount == 0) return;
      var msg = (g._language == 'v' ? 'Hệ thống sẽ <span class="TaskDialogContentHighlight">xóa tất cả dữ liệu tự nhập</span>, bạn có chắc chắn xóa không?' : 'Are you sure you want to <span class="TaskDialogContentHighlight">delete all manually enter data</span>?');
      var id = g.get_id()
      $message.show(msg, 0, String.format('clearGrid(\'{0}\');', id), String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function request$Posting(g, c) {
  if (g._rowCount == 0 || g._arrValue.length == 0) return;
  var count = 4000, concurrent = 10, temp = '', q = '', index = 0, arr = [], maxlength = g._arrValue.length;
  for (var i = 0; i < g._arrValue.length; i++) {
    temp = getValue(g._arrValue[i]);
    if ((q + temp).length <= count) q = q + (q != '' ? ',' : '') + temp;
    else {
      arr[arr.length] = q;
      q = temp;
    }
  }
  if (q != '') arr[arr.length] = q;

   var r = (g._activeCell ? g._activeRow : 1), o = g._getItemValue(r, g._$f), str = [], length = arr.length;
  o.row = r;
  g._finish = (parseInt(length / concurrent)) + ((length % concurrent == 0) ? 0 : 1);

  Array.add(str, ['ma_dvcs', 'String', g._unit]);
  Array.add(str, ['ky1', 'String', g._periodFrom]);
  Array.add(str, ['nam1', 'String', g._yearFrom]);
  Array.add(str, ['ky2', 'String', g._periodTo]);
  Array.add(str, ['nam2', 'String', g._yearTo]);
  Array.add(str, ['form', 'String', g._form]);

  var paraFixed = str.length;
  for (var i = 0; i < length; i++) {
    if (index == concurrent) {
      index = 0;
      g.request(o, c, c, str);
      str.splice(paraFixed, concurrent);
    }
    index++;
    Array.add(str, ['k' + index, 'String', arr[i]);
  }
  if (index <= concurrent && index > 0) {
    for (index += 1; index <= concurrent; index++) { Array.add(str, ['k' + index, 'String', ''); }
    g.request(o, c, c, str);
  }
  arr = str = [];
}
/* </flatten> */

function onChange$&defaultName;(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'gt':
    case 'ts':
    case 'danh_gia':
      addArray(g);
      break;
    default:
      break;
  }
}

function on$&defaultName;$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm, id = g.get_id(), v = g._language == 'v';
  var m1 = v ? 'Chương trình đã thực hiện xong.' : 'The process was completed successfully.', m2 = v ? 'Phát sinh lỗi trong quá trình thực hiện.' : 'The process was failed.';
  switch (context) {
    case 'Save':
      g._finish--;
      if (result[0].Value == '') {
        if (g._finish == 0) {
          g._arrValue = [];
          $message.show(m1, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
        }
      }
      else $message.show(m2, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      break;
    case 'Clear':
      if (result[0].Value == '') {
          g._arrValue = [];
          $message.show(m1, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      }
      else $message.show(m2, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      break;
    default:
      break;
  }
}

function fill$&defaultName;(g) {
  if (g._gridRefresh) {
    g._arrValue = [];
    g._gridRefresh = false;
    return;
  }
  if (g._arrValue.length == 0) return;

  var column = 0, name;
  for (var r = 1; r <= g._rowCount; r++) {
    for (var i = 0; i < g._arrValue.length; i++) {
      if (g._arrValue[i][0][1] == g._getItemValue(r, g._$c)) {
        for(var k = 1; k < g._arrValue[i].length; k++) {
          name = g._arrValue[i][k][0];
          column = name.substring(name.lastIndexOf(String.fromCharCode(235)) + 1);
          g._setItemValue(r, column, g._arrValue[i][k][1]);
        }
      }
    }
  }
}
/* <flatten type="Javascript"> */
function addArray(g) {
  var key = g._getItemValue(g._activeRow, g._$c), columnName = g._activeCell.field.Name, columnIndex = g._getColumnOrder(columnName);
  var add = false, activeColumn = (columnIndex == g._$gt ? g._$cotgt : (columnIndex == g._$ts ? g._$cotts : g._$cotdg));
  var subItemName = activeColumn + String.fromCharCode(235) + ((activeColumn != g._$cotdg) ? '1' : columnName.substring(columnName.indexOf('$') + 1)) + String.fromCharCode(235) + columnIndex;
  var flag = false, length = 0, item = [,];
  Array.add(item, ['ma_so' + String.fromCharCode(235), key]);
  Array.add(item, [subItemName, g._getItemValue(g._activeRow, columnIndex)]);
  for (var i = 0; i < g._arrValue.length; i++) {
    if (g._arrValue[i][0][1] == key) {
      flag = false, length = g._arrValue[i].length;
      for (var j = 0; j < length; j++) {
        if (g._arrValue[i][j][0] == item[1][0]) {
          g._arrValue[i][j][1] = item[1][1];
          flag = 1;
          break;
        }
      }
      if (!flag) g._arrValue[i].splice(length, 0, item[1]);
      add = true;
      return;
    }
  }
  if (!add) Array.add(g._arrValue, item);
}

function getValue(arr) {
  var q = '';
  for (var i = 0; i < arr.length; i++) {
    q = q + (q == '' ? '': String.fromCharCode(252)) + (arr[i][0]).substring(0, (arr[i][0]).lastIndexOf(String.fromCharCode(235)) + 1) + '' + (arr[i][1]).toString().replace(/,/g, String.fromCharCode(255));
  }
  return q;
}

function clearGrid(id) {
  var g = $find(id);
  if (g._rowCount == 0) return;

  var r = (g._activeCell ? g._activeRow : 1), o = g._getItemValue(r, g._$f), str = [];
  o.row = r;
  Array.add(str, ['ma_dvcs', 'String', g._unit]);
  Array.add(str, ['ky1', 'String', g._periodFrom]);
  Array.add(str, ['nam1', 'String', g._yearFrom]);
  Array.add(str, ['ky2', 'String', g._periodTo]);
  Array.add(str, ['nam2', 'String', g._yearTo]);
  Array.add(str, ['form', 'String', g._form]);
  g.request(o, 'Clear', 'Clear', str);
}

function readOnlyCell(g) {
  var l0 = g._getColumnOrder('kind'), l1 = g._getColumnOrder('gt'), l2 = g._getColumnOrder('ts');
  for (i = 1; i <= g._rowCount; i++)  {
    if (g._getItemValue(i, l0) != '9') {
      var o1 = g._getItem(i, l1), o2 = g._getItem(i, l2);
      if ($func.isIF) o1.readOnly = o2.readOnly = true;
        else {
          $addHandler(o1, "keydown", readOnlyHandler);
          $addHandler(o2, "keydown", readOnlyHandler);
        }
    }
  }
}

function readOnlyHandler(e) {
  var k = $func.keyCode(e);
  if (k != 13 && !($func.isNavKey(e))) $func.cancelEvent(e);
}
/* </flatten> */
